package uth.nhathuy.Cart.config;

import lombok.RequiredArgsConstructor;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;
import uth.nhathuy.Cart.entity.Cart;
import uth.nhathuy.Cart.entity.CartItem;
import uth.nhathuy.Cart.repository.CartItemRepository;
import uth.nhathuy.Cart.repository.CartRepository;

import java.math.BigDecimal;
import java.util.List;

@Component
@Profile("seed")
@RequiredArgsConstructor
public class DataSeeder implements CommandLineRunner {

    private final CartRepository cartRepository;
    private final CartItemRepository cartItemRepository;

    @Override
    public void run(String... args) {
        if (cartRepository.count() > 0) {
            return;
        }

        Cart userCart = cartRepository.save(Cart.builder().userId(3L).build());

        List<CartItem> items = List.of(
                CartItem.builder()
                        .cart(userCart)
                        .productId(1L)
                        .variantId(1L)
                        .productName("MacBook Air M3 13 inch")
                        .variantName("Midnight / 8GB / 256GB")
                        .thumbnail("https://images.unsplash.com/photo-1517336714739-489689fd1ca8?w=600")
                        .price(new BigDecimal("25990000"))
                        .quantity(1)
                        .build(),
                CartItem.builder()
                        .cart(userCart)
                        .productId(5L)
                        .variantId(9L)
                        .productName("Keychron K2 Wireless")
                        .variantName("Brown Switch")
                        .thumbnail("https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=600")
                        .price(new BigDecimal("1990000"))
                        .quantity(1)
                        .build()
        );

        cartItemRepository.saveAll(items);
    }
}

package uth.nhathuy.Inventory.config;

import lombok.RequiredArgsConstructor;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;
import uth.nhathuy.Inventory.entity.Inventory;
import uth.nhathuy.Inventory.entity.InventoryStatus;
import uth.nhathuy.Inventory.entity.InventoryTransaction;
import uth.nhathuy.Inventory.entity.InventoryTransactionType;
import uth.nhathuy.Inventory.repository.InventoryRepository;
import uth.nhathuy.Inventory.repository.InventoryTransactionRepository;

import java.util.ArrayList;
import java.util.List;

@Component
@Profile("seed")
@RequiredArgsConstructor
public class DataSeeder implements CommandLineRunner {

    private final InventoryRepository inventoryRepository;
    private final InventoryTransactionRepository transactionRepository;

    @Override
    public void run(String... args) {
        if (inventoryRepository.count() > 0) {
            return;
        }

        List<Inventory> inventories = new ArrayList<>();
        inventories.add(buildInventory(1L, 1L, 40, 2, 5));
        inventories.add(buildInventory(1L, 2L, 24, 1, 5));
        inventories.add(buildInventory(2L, 3L, 18, 1, 5));
        inventories.add(buildInventory(2L, 4L, 8, 0, 5));
        inventories.add(buildInventory(3L, 5L, 36, 3, 5));
        inventories.add(buildInventory(3L, 6L, 16, 1, 5));
        inventories.add(buildInventory(4L, 7L, 20, 0, 5));
        inventories.add(buildInventory(4L, 8L, 10, 0, 5));
        inventories.add(buildInventory(5L, 9L, 55, 4, 5));

        List<Inventory> saved = inventoryRepository.saveAll(inventories);

        List<InventoryTransaction> transactions = saved.stream()
                .map(item -> InventoryTransaction.builder()
                        .inventoryId(item.getId())
                        .productId(item.getProductId())
                        .variantId(item.getVariantId())
                        .type(InventoryTransactionType.IMPORT)
                        .quantity(item.getAvailableQuantity())
                        .note("Seed initial stock")
                        .build())
                .toList();

        transactionRepository.saveAll(transactions);
    }

    private Inventory buildInventory(Long productId, Long variantId, int available, int reserved, int threshold) {
        return Inventory.builder()
                .productId(productId)
                .variantId(variantId)
                .availableQuantity(available)
                .reservedQuantity(reserved)
                .lowStockThreshold(threshold)
                .status(resolveStatus(available, threshold))
                .build();
    }

    private InventoryStatus resolveStatus(int availableQuantity, int threshold) {
        if (availableQuantity <= 0) {
            return InventoryStatus.OUT_OF_STOCK;
        }
        if (availableQuantity <= threshold) {
            return InventoryStatus.LOW_STOCK;
        }
        return InventoryStatus.IN_STOCK;
    }
}

package uth.nhathuy.Order.config;

import lombok.RequiredArgsConstructor;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;
import uth.nhathuy.Order.entity.Order;
import uth.nhathuy.Order.entity.OrderItem;
import uth.nhathuy.Order.entity.OrderStatus;
import uth.nhathuy.Order.repository.OrderRepository;

import java.math.BigDecimal;
import java.util.List;

@Component
@Profile("seed")
@RequiredArgsConstructor
public class DataSeeder implements CommandLineRunner {

    private final OrderRepository orderRepository;

    @Override
    public void run(String... args) {
        if (orderRepository.count() > 0) {
            return;
        }

        seedOrder(
                3L,
                "user",
                "Normal User",
                "0900000003",
                "456 Le Loi, Phuong Ben Thanh, Quan 1, TP HCM",
                "Giao gio hanh chinh",
                OrderStatus.COMPLETED,
                "SUCCESS",
                List.of(
                        new ItemSeed(1L, 1L, "MacBook Air M3 13 inch", "Midnight / 8GB / 256GB", "https://images.unsplash.com/photo-1517336714739-489689fd1ca8?w=600", "25990000", 1),
                        new ItemSeed(5L, 9L, "Keychron K2 Wireless", "Brown Switch", "https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=600", "1990000", 1)
                )
        );

        seedOrder(
                3L,
                "user",
                "Normal User",
                "0900000003",
                "456 Le Loi, Phuong Ben Thanh, Quan 1, TP HCM",
                "Goi truoc khi giao",
                OrderStatus.SHIPPING,
                "PENDING",
                List.of(
                        new ItemSeed(3L, 5L, "iPhone 15 Pro Max", "Titan Tu Nhien / 256GB", "https://images.unsplash.com/photo-1695048133142-1a20484d2569?w=600", "31990000", 1)
                )
        );
    }

    private void seedOrder(
            Long userId,
            String username,
            String customerName,
            String phone,
            String address,
            String note,
            OrderStatus status,
            String paymentStatus,
            List<ItemSeed> itemSeeds
    ) {
        Order order = Order.builder()
                .userId(userId)
                .username(username)
                .customerName(customerName)
                .phone(phone)
                .address(address)
                .note(note)
                .status(status)
                .paymentStatus(paymentStatus)
                .build();

        BigDecimal total = BigDecimal.ZERO;
        for (ItemSeed seed : itemSeeds) {
            BigDecimal price = new BigDecimal(seed.price());
            BigDecimal lineTotal = price.multiply(BigDecimal.valueOf(seed.quantity()));
            total = total.add(lineTotal);

            OrderItem item = OrderItem.builder()
                    .order(order)
                    .productId(seed.productId())
                    .variantId(seed.variantId())
                    .productName(seed.productName())
                    .variantName(seed.variantName())
                    .thumbnail(seed.thumbnail())
                    .price(price)
                    .quantity(seed.quantity())
                    .lineTotal(lineTotal)
                    .build();

            order.getItems().add(item);
        }

        order.setTotalAmount(total);
        orderRepository.save(order);
    }

    private record ItemSeed(
            Long productId,
            Long variantId,
            String productName,
            String variantName,
            String thumbnail,
            String price,
            int quantity
    ) {
    }
}

package uth.nhathuy.Payment.config;

import lombok.RequiredArgsConstructor;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;
import uth.nhathuy.Payment.entity.Payment;
import uth.nhathuy.Payment.entity.PaymentMethod;
import uth.nhathuy.Payment.entity.PaymentStatus;
import uth.nhathuy.Payment.repository.PaymentRepository;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

@Component
@Profile("seed")
@RequiredArgsConstructor
public class DataSeeder implements CommandLineRunner {

    private final PaymentRepository paymentRepository;

    @Override
    public void run(String... args) {
        if (paymentRepository.count() > 0) {
            return;
        }

        Payment payment1 = Payment.builder()
                .orderId(1L)
                .userId(3L)
                .amount(new BigDecimal("27980000"))
                .method(PaymentMethod.BANK_TRANSFER)
                .status(PaymentStatus.SUCCESS)
                .transactionRef("SEED-TXN-0001")
                .paymentUrl(null)
                .note("Seed paid order")
                .paidAt(LocalDateTime.now().minusDays(2))
                .build();

        Payment payment2 = Payment.builder()
                .orderId(2L)
                .userId(3L)
                .amount(new BigDecimal("31990000"))
                .method(PaymentMethod.COD)
                .status(PaymentStatus.PENDING)
                .transactionRef("SEED-TXN-0002")
                .paymentUrl("https://sandbox-pay.example.com/orders/2")
                .note("Seed pending COD")
                .build();

        paymentRepository.saveAll(List.of(payment1, payment2));
    }
}

package uth.nhathuy.Product.config;

import lombok.RequiredArgsConstructor;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;
import uth.nhathuy.Product.entity.*;
import uth.nhathuy.Product.repository.*;

import java.math.BigDecimal;
import java.util.List;

@Component
@Profile("seed")
@RequiredArgsConstructor
public class DataSeeder implements CommandLineRunner {

    private final CategoryRepository categoryRepository;
    private final ProductRepository productRepository;
    private final ProductVariantRepository variantRepository;
    private final ProductSpecificationRepository specificationRepository;
    private final ProductImageRepository imageRepository;

    @Override
    public void run(String... args) {
        Category laptop = upsertCategory("Laptop", "laptop", true);
        Category smartphone = upsertCategory("Dien thoai", "dien-thoai", true);
        Category monitor = upsertCategory("Man hinh", "man-hinh", true);
        Category accessories = upsertCategory("Phu kien", "phu-kien", true);

        Product macbook = upsertProduct(
                "MacBook Air M3 13 inch",
                "macbook-air-m3-13",
                "Apple",
                laptop,
                "Laptop sieu nhe cho hoc tap va cong viec",
                "MacBook Air M3 13 inch vo nhom, pin ben, man hinh dep va hieu nang tot cho nhu cau hieu suat cao.",
                "https://images.unsplash.com/photo-1517336714739-489689fd1ca8?w=1200",
                ProductStatus.ACTIVE,
                true
        );
        upsertVariant(macbook, "MBA-M3-8-256", "Midnight", "8GB", "256GB", "Base", "27990000", "25990000", 40, "https://images.unsplash.com/photo-1517336714739-489689fd1ca8?w=1000", VariantStatus.ACTIVE);
        upsertVariant(macbook, "MBA-M3-16-512", "Silver", "16GB", "512GB", "Premium", "34990000", "32990000", 24, "https://images.unsplash.com/photo-1541807084-5c52b6b3adef?w=1000", VariantStatus.ACTIVE);
        seedSpecificationsIfMissing(macbook, List.of(
                spec(macbook, "Hieu nang", "CPU", "Apple M3", 1),
                spec(macbook, "Hieu nang", "RAM", "8GB/16GB", 2),
                spec(macbook, "Man hinh", "Kich thuoc", "13.6 inch Liquid Retina", 3),
                spec(macbook, "Pin", "Thoi luong", "Den 18 gio", 4)
        ));
        seedImagesIfMissing(macbook, List.of(
                image(macbook, "https://images.unsplash.com/photo-1517336714739-489689fd1ca8?w=1200", true, 1),
                image(macbook, "https://images.unsplash.com/photo-1541807084-5c52b6b3adef?w=1200", false, 2)
        ));

        Product rog = upsertProduct(
                "ASUS ROG Zephyrus G14",
                "asus-rog-zephyrus-g14",
                "ASUS",
                laptop,
                "Laptop gaming gon nhe, man dep",
                "ROG Zephyrus G14 toi uu cho gaming va sang tao noi dung voi GPU manh me, tan nhiet tot.",
                "https://images.unsplash.com/photo-1611078489935-0cb964de46d6?w=1200",
                ProductStatus.ACTIVE,
                true
        );
        upsertVariant(rog, "ROG-G14-16-1TB", "Moonlight White", "16GB", "1TB", "RTX 4060", "45990000", "42990000", 18, "https://images.unsplash.com/photo-1611078489935-0cb964de46d6?w=1000", VariantStatus.ACTIVE);
        upsertVariant(rog, "ROG-G14-32-1TB", "Eclipse Gray", "32GB", "1TB", "RTX 4070", "54990000", null, 8, "https://images.unsplash.com/photo-1593642702821-c8da6771f0c6?w=1000", VariantStatus.ACTIVE);
        seedSpecificationsIfMissing(rog, List.of(
                spec(rog, "Hieu nang", "CPU", "AMD Ryzen 9", 1),
                spec(rog, "Hieu nang", "GPU", "NVIDIA RTX 4060/4070", 2),
                spec(rog, "Man hinh", "Tan so quet", "165Hz", 3),
                spec(rog, "Khoi luong", "Can nang", "1.65kg", 4)
        ));
        seedImagesIfMissing(rog, List.of(
                image(rog, "https://images.unsplash.com/photo-1611078489935-0cb964de46d6?w=1200", true, 1),
                image(rog, "https://images.unsplash.com/photo-1593642702821-c8da6771f0c6?w=1200", false, 2)
        ));

        Product iphone = upsertProduct(
                "iPhone 15 Pro Max",
                "iphone-15-pro-max",
                "Apple",
                smartphone,
                "Flagship camera va hieu nang cao",
                "iPhone 15 Pro Max khung titan, camera zoom 5x va chip A17 Pro cho trai nghiem cao cap.",
                "https://images.unsplash.com/photo-1695048133142-1a20484d2569?w=1200",
                ProductStatus.ACTIVE,
                true
        );
        upsertVariant(iphone, "IP15PM-256-TN", "Titan Tu Nhien", "8GB", "256GB", "Standard", "33990000", "31990000", 36, "https://images.unsplash.com/photo-1695048133142-1a20484d2569?w=1000", VariantStatus.ACTIVE);
        upsertVariant(iphone, "IP15PM-512-BL", "Titan Xanh", "8GB", "512GB", "Pro Storage", "39990000", null, 16, "https://images.unsplash.com/photo-1605236453806-6ff36851218e?w=1000", VariantStatus.ACTIVE);
        seedSpecificationsIfMissing(iphone, List.of(
                spec(iphone, "Camera", "Camera chinh", "48MP", 1),
                spec(iphone, "Man hinh", "Do sang", "2000 nits", 2),
                spec(iphone, "Pin", "Sac nhanh", "USB-C", 3),
                spec(iphone, "Hieu nang", "Chip", "A17 Pro", 4)
        ));
        seedImagesIfMissing(iphone, List.of(
                image(iphone, "https://images.unsplash.com/photo-1695048133142-1a20484d2569?w=1200", true, 1),
                image(iphone, "https://images.unsplash.com/photo-1605236453806-6ff36851218e?w=1200", false, 2)
        ));

        Product monitorProduct = upsertProduct(
                "LG UltraFine 27 inch 4K",
                "lg-ultrafine-27-4k",
                "LG",
                monitor,
                "Man hinh 4K cho cong viec sang tao",
                "Man hinh LG UltraFine 27 inch 4K voi mau sac chuan va ket noi da dang cho workstation.",
                "https://images.unsplash.com/photo-1527443224154-c4a3942d3acf?w=1200",
                ProductStatus.ACTIVE,
                false
        );
        upsertVariant(monitorProduct, "LG-UF27-4K", "Den", "-", "-", "27 inch", "11990000", "9990000", 20, "https://images.unsplash.com/photo-1527443224154-c4a3942d3acf?w=1000", VariantStatus.ACTIVE);
        upsertVariant(monitorProduct, "LG-UF32-4K", "Den", "-", "-", "32 inch", "14990000", null, 10, "https://images.unsplash.com/photo-1546538915-a9e2c8d8330b?w=1000", VariantStatus.ACTIVE);
        seedSpecificationsIfMissing(monitorProduct, List.of(
                spec(monitorProduct, "Thong so", "Do phan giai", "4K UHD", 1),
                spec(monitorProduct, "Thong so", "Tam nen", "IPS", 2),
                spec(monitorProduct, "Ket noi", "Cong", "HDMI/DisplayPort/USB-C", 3)
        ));
        seedImagesIfMissing(monitorProduct, List.of(
                image(monitorProduct, "https://images.unsplash.com/photo-1527443224154-c4a3942d3acf?w=1200", true, 1),
                image(monitorProduct, "https://images.unsplash.com/photo-1546538915-a9e2c8d8330b?w=1200", false, 2)
        ));

        Product keyboard = upsertProduct(
                "Keychron K2 Wireless",
                "keychron-k2-wireless",
                "Keychron",
                accessories,
                "Ban phim co khong day da nen tang",
                "Keychron K2 layout gon, ho tro bluetooth va hot-swap, phu hop cho ca macOS va Windows.",
                "https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=1200",
                ProductStatus.ACTIVE,
                false
        );
        upsertVariant(keyboard, "K2-BROWN", "Xam", "-", "-", "Brown Switch", "2290000", "1990000", 55, "https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=1000", VariantStatus.ACTIVE);
        seedSpecificationsIfMissing(keyboard, List.of(
                spec(keyboard, "Ket noi", "Bluetooth", "Bluetooth 5.1", 1),
                spec(keyboard, "Pin", "Dung luong", "4000mAh", 2),
                spec(keyboard, "Switch", "Loai", "Gateron Brown", 3)
        ));
        seedImagesIfMissing(keyboard, List.of(
                image(keyboard, "https://images.unsplash.com/photo-1618384887929-16ec33fab9ef?w=1200", true, 1)
        ));
    }

    private Category upsertCategory(String name, String slug, boolean active) {
        return categoryRepository.findBySlug(slug)
                .map(existing -> {
                    existing.setName(name);
                    existing.setActive(active);
                    return categoryRepository.save(existing);
                })
                .orElseGet(() -> categoryRepository.save(Category.builder()
                        .name(name)
                        .slug(slug)
                        .active(active)
                        .build()));
    }

    private Product upsertProduct(
            String name,
            String slug,
            String brand,
            Category category,
            String shortDescription,
            String description,
            String thumbnail,
            ProductStatus status,
            boolean featured
    ) {
        return productRepository.findBySlug(slug)
                .map(existing -> {
                    existing.setName(name);
                    existing.setBrand(brand);
                    existing.setCategory(category);
                    existing.setShortDescription(shortDescription);
                    existing.setDescription(description);
                    existing.setThumbnail(thumbnail);
                    existing.setStatus(status);
                    existing.setFeatured(featured);
                    return productRepository.save(existing);
                })
                .orElseGet(() -> productRepository.save(Product.builder()
                        .name(name)
                        .slug(slug)
                        .brand(brand)
                        .category(category)
                        .shortDescription(shortDescription)
                        .description(description)
                        .thumbnail(thumbnail)
                        .status(status)
                        .featured(featured)
                        .build()));
    }

    private void upsertVariant(
            Product product,
            String sku,
            String color,
            String ram,
            String storage,
            String versionName,
            String price,
            String salePrice,
            int stockQuantity,
            String imageUrl,
            VariantStatus status
    ) {
        variantRepository.findBySku(sku)
                .map(existing -> {
                    existing.setProduct(product);
                    existing.setColor(color);
                    existing.setRam(ram);
                    existing.setStorage(storage);
                    existing.setVersionName(versionName);
                    existing.setPrice(new BigDecimal(price));
                    existing.setSalePrice(salePrice == null ? null : new BigDecimal(salePrice));
                    existing.setStockQuantity(stockQuantity);
                    existing.setImageUrl(imageUrl);
                    existing.setStatus(status);
                    return variantRepository.save(existing);
                })
                .orElseGet(() -> variantRepository.save(ProductVariant.builder()
                        .product(product)
                        .sku(sku)
                        .color(color)
                        .ram(ram)
                        .storage(storage)
                        .versionName(versionName)
                        .price(new BigDecimal(price))
                        .salePrice(salePrice == null ? null : new BigDecimal(salePrice))
                        .stockQuantity(stockQuantity)
                        .imageUrl(imageUrl)
                        .status(status)
                        .build()));
    }

    private void seedSpecificationsIfMissing(Product product, List<ProductSpecification> specifications) {
        if (!specificationRepository.findByProductIdOrderByGroupNameAscSortOrderAscIdAsc(product.getId()).isEmpty()) {
            return;
        }
        specificationRepository.saveAll(specifications);
    }

    private void seedImagesIfMissing(Product product, List<ProductImage> images) {
        if (!imageRepository.findByProductIdOrderBySortOrderAscIdAsc(product.getId()).isEmpty()) {
            return;
        }
        imageRepository.saveAll(images);
    }

    private ProductSpecification spec(Product product, String group, String key, String value, int order) {
        return ProductSpecification.builder()
                .product(product)
                .groupName(group)
                .specKey(key)
                .specValue(value)
                .sortOrder(order)
                .build();
    }

    private ProductImage image(Product product, String imageUrl, boolean thumbnail, int sortOrder) {
        return ProductImage.builder()
                .product(product)
                .imageUrl(imageUrl)
                .thumbnail(thumbnail)
                .sortOrder(sortOrder)
                .build();
    }
}

package uth.nhathuy.User.config;

import lombok.RequiredArgsConstructor;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;
import uth.nhathuy.User.entity.Address;
import uth.nhathuy.User.entity.UserProfile;
import uth.nhathuy.User.repository.AddressRepository;
import uth.nhathuy.User.repository.UserProfileRepository;

import java.time.LocalDate;

@Component
@Profile("seed")
@RequiredArgsConstructor
public class DataSeeder implements CommandLineRunner {

    private final UserProfileRepository userProfileRepository;
    private final AddressRepository addressRepository;

    @Override
    public void run(String... args) {
        seedProfileAndAddress(
                1L,
                "admin",
                "admin@gmail.com",
                "System Admin",
                "ADMIN",
                "0900000001",
                "Toa nha NovaGear",
                "Phuong Ben Nghe",
                "Quan 1",
                "TP HCM"
        );
        seedProfileAndAddress(
                2L,
                "staff",
                "staff@gmail.com",
                "Staff User",
                "STAFF",
                "0900000002",
                "123 Nguyen Van Linh",
                "Tan Phong",
                "Quan 7",
                "TP HCM"
        );
        seedProfileAndAddress(
                3L,
                "user",
                "user@gmail.com",
                "Normal User",
                "USER",
                "0900000003",
                "456 Le Loi",
                "Phuong Ben Thanh",
                "Quan 1",
                "TP HCM"
        );
    }

    private void seedProfileAndAddress(
            Long authUserId,
            String username,
            String email,
            String fullName,
            String role,
            String phone,
            String line1,
            String ward,
            String district,
            String province
    ) {
        UserProfile profile = userProfileRepository.findByAuthUserId(authUserId)
                .orElseGet(() -> UserProfile.builder().authUserId(authUserId).build());

        profile.setUsername(username);
        profile.setEmail(email);
        profile.setFullName(fullName);
        profile.setRole(role);
        profile.setStatus("ACTIVE");
        profile.setPhone(phone);
        profile.setGender("MALE");
        profile.setDateOfBirth(LocalDate.of(1998, 1, 1));

        userProfileRepository.save(profile);

        if (addressRepository.findByAuthUserIdOrderByIsDefaultDescIdDesc(authUserId).isEmpty()) {
            addressRepository.save(Address.builder()
                    .authUserId(authUserId)
                    .receiverName(fullName)
                    .receiverPhone(phone)
                    .line1(line1)
                    .line2("")
                    .ward(ward)
                    .district(district)
                    .province(province)
                    .postalCode("700000")
                    .isDefault(true)
                    .build());
        }
    }
}

