return { id: item?.id ?? item?.productId ?? "", slug: item?.slug ?? "", name: item?.name ?? "", description: item?.shortDescription ?? item?.description ?? "", imageUrl: item?.thumbnail ?? firstVariant?.imageUrl ?? thumbImage ?? firstImage ?? item?.imageUrl ?? "", price: Number(firstVariant?.price ?? item?.price ?? 0), salePrice: firstVariant?.salePrice != null ? Number(firstVariant.salePrice) : item?.salePrice != null ? Number(item.salePrice) : undefined, stock: firstVariant?.stockQuantity != null ? Number(firstVariant.stockQuantity) : item?.stock != null ? Number(item.stock) : 0, category: categoryName, brand: item?.brand ?? "", } }
function buildVariantLabel(source?: RawVariant | RawCartItem): string { return [ source?.color, source?.ram, source?.storage, source?.versionName, ] .filter(Boolean) .join(" / ") }
function mapCartItem(item: RawCartItem): CartItem { const variantSource = item.variant ?? item.productVariant ?? item
return { id: item.id ?? "", productId: item.productId ?? item.product?.id ?? "", variantId: item.variantId ?? item.variant?.id ?? item.productVariant?.id ?? "", quantity: Number(item.quantity ?? 0), variantSku: item.variant?.sku ?? item.productVariant?.sku ?? item.sku ?? "", variantLabel: buildVariantLabel(variantSource), product: item.product ? mapProduct(item.product) : undefined, } }
export async function getMyCart(): Promise<CartItem[]> { const res = await axiosClient.get("/cart") const items = Array.isArray(res.data) ? res.data : res.data?.items ?? [] return items.map(mapCartItem) }
