import {useState} from "react"
import {Link, useNavigate} from "react-router-dom"
import {getMeApi, loginApi} from "../api/authApi"
import {bootstrapMyProfile, getMyProfile} from "../api/userApi"
import {setStoredUser, setToken} from "../utils/auth"

// Chuẩn hóa kiểm tra Role: Chấp nhận ADMIN, ROLE_ADMIN hoặc mảng chứa chúng
function getNormalizedRole(authData: any): string {
    const rawRole = Array.isArray(authData?.roles) ? authData.roles[0] : (authData?.role || authData?.roles);
    if (!rawRole) return "USER";

    // Xử lý nếu Role bị dính tiền tố ROLE_ từ Spring Security
    const cleanRole = String(rawRole).replace("ROLE_", "").toUpperCase();
    return cleanRole;
}

export default function LoginPage() {
    const navigate = useNavigate()
    const [form, setForm] = useState({
        username: "",
        password: "",
    })
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState("")

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        try {
            setLoading(true)
            setError("")

            // 1. Đăng nhập lấy Token
            const res = await loginApi(form)
            const token = res.token || res.accessToken || res.data?.token

            if (!token) {
                throw new Error("Hệ thống không trả về Token xác thực")
            }

            // Lưu Token vào LocalStorage ngay lập tức
            setToken(token)

            // 2. Lấy thông tin tài khoản và Profile
            let authMe: any = null
            let profile: any = null

            try {
                // Gọi song song để tiết kiệm thời gian
                const [meRes, _] = await Promise.all([
                    getMeApi(),
                    bootstrapMyProfile().catch(() => null) // Tạo profile nếu chưa có
                ]);
                authMe = meRes.data || meRes;
                profile = await getMyProfile().catch(() => null);
            } catch (err) {
                console.warn("Không thể lấy đầy đủ Profile thông qua Gateway:", err);
            }

            // 3. Chuẩn hóa Role để AdminRoute không bị lỗi
            const finalRole = getNormalizedRole(authMe || profile);

            // 4. Lưu User vào LocalStorage
            setStoredUser({
                id: authMe?.id ?? profile?.id,
                username: authMe?.username ?? profile?.username ?? form.username,
                email: authMe?.email ?? profile?.email,
                fullName: profile?.fullName ?? authMe?.fullName ?? "Nguyễn Nhất Huy",
                role: finalRole,
            })

            // 5. Điều hướng dựa trên Role
            if (finalRole === "ADMIN") {
                navigate("/admin", {replace: true})
            } else {
                navigate("/", {replace: true})
            }

            // Ép render lại để cập nhật Auth State toàn hệ thống
            window.location.reload()

        } catch (err: any) {
            console.error("Login Error:", err)
            const serverError = err.response?.data?.message || err.response?.data?.error
            setError(serverError || "Tên đăng nhập hoặc mật khẩu không đúng")
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="flex min-h-screen items-center justify-center bg-brand-light px-4">
            <form
                onSubmit={handleSubmit}
                className="w-full max-w-md rounded-3xl bg-white p-8 shadow-lg animate-in fade-in duration-500"
            >
                <div className="text-center">
                    <h1 className="text-3xl font-bold text-brand-dark">Đăng nhập</h1>
                    <p className="mt-2 text-sm text-brand-gray">Chào mừng quay lại NovaGear</p>
                </div>

                <div className="mt-8 space-y-4">
                    <div className="space-y-1">
                        <label className="ml-1 text-xs font-bold uppercase text-brand-gray">Tên đăng nhập</label>
                        <input
                            type="text"
                            placeholder="Nhập username..."
                            className="w-full rounded-xl border border-gray-200 px-4 py-3 outline-none focus:border-brand-dark transition-all"
                            value={form.username}
                            onChange={(e) => setForm({...form, username: e.target.value})}
                            required
                        />
                    </div>

                    <div className="space-y-1">
                        <label className="ml-1 text-xs font-bold uppercase text-brand-gray">Mật khẩu</label>
                        <input
                            type="password"
                            placeholder="••••••••"
                            className="w-full rounded-xl border border-gray-200 px-4 py-3 outline-none focus:border-brand-dark transition-all"
                            value={form.password}
                            onChange={(e) => setForm({...form, password: e.target.value})}
                            required
                        />
                    </div>
                </div>

                {error && (
                    <div className="mt-4 rounded-xl border border-red-100 bg-red-50 p-3">
                        <p className="text-xs font-medium text-red-500">{error}</p>
                    </div>
                )}

                <button
                    type="submit"
                    disabled={loading}
                    className="mt-8 w-full rounded-xl bg-brand-dark py-3.5 font-bold text-white shadow-md transition-all hover:bg-black disabled:cursor-not-allowed disabled:bg-gray-400"
                >
                    {loading ? "Đang xử lý..." : "Đăng nhập ngay"}
                </button>

                <p className="mt-6 text-center text-sm text-brand-gray">
                    Chưa có tài khoản? <Link to="/register" className="font-bold text-blue-600 hover:underline">Đăng ký
                    ngay</Link>
                </p>
            </form>
        </div>
    )
}

import {useState} from "react"
import {Link, useNavigate} from "react-router-dom"
import {getMeApi, loginApi} from "../api/authApi"
import {bootstrapMyProfile, getMyProfile, type UserProfile} from "../api/userApi"
import {setStoredUser, setToken} from "../utils/auth"

type AuthIdentity = {
    id?: number | string
    username?: string
    email?: string
    fullName?: string
    role?: string
    roles?: string[] | string
}

type ApiErrorLike = {
    response?: {
        data?: {
            message?: string
            error?: string
        }
    }
}

// Chuẩn hóa kiểm tra Role: Chấp nhận ADMIN, ROLE_ADMIN hoặc mảng chứa chúng
function getNormalizedRole(authData: AuthIdentity | null | undefined): string {
    const rawRole = Array.isArray(authData?.roles) ? authData.roles[0] : (authData?.role || authData?.roles)
    if (!rawRole) return "USER"

    // Xử lý nếu Role bị dính tiền tố ROLE_ từ Spring Security
    const cleanRole = String(rawRole).replace("ROLE_", "").toUpperCase()
    return cleanRole
}

export default function LoginPage() {
    const navigate = useNavigate()
    const [form, setForm] = useState({
        username: "",
        password: "",
    })
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState("")

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        try {
            setLoading(true)
            setError("")

            // 1. Đăng nhập lấy Token
            const res = await loginApi(form)
            const token = res.token || res.accessToken || res.data?.token

            if (!token) {
                throw new Error("Hệ thống không trả về Token xác thực")
            }

            // Lưu Token vào LocalStorage ngay lập tức
            setToken(token)

            // 2. Lấy thông tin tài khoản và Profile
            let authMe: AuthIdentity | null = null
            let profile: UserProfile | null = null

            try {
                // Gọi song song để tiết kiệm thời gian
                const [meRes] = await Promise.all([
                    getMeApi(),
                    bootstrapMyProfile().catch(() => null) // Tạo profile nếu chưa có
                ])
                authMe = meRes
                profile = await getMyProfile().catch(() => null)
            } catch (err) {
                console.warn("Không thể lấy đầy đủ Profile thông qua Gateway:", err)
            }

            // 3. Chuẩn hóa Role để AdminRoute không bị lỗi
            const finalRole = getNormalizedRole(authMe ?? profile)

            // 4. Lưu User vào LocalStorage
            setStoredUser({
                id: authMe?.id ?? profile?.id,
                username: authMe?.username ?? profile?.username ?? form.username,
                email: authMe?.email ?? profile?.email,
                fullName: profile?.fullName ?? authMe?.fullName ?? "Nguyễn Nhất Huy",
                role: finalRole,
            })

            // 5. Điều hướng dựa trên Role
            if (finalRole === "ADMIN") {
                navigate("/admin", {replace: true})
            } else {
                navigate("/", {replace: true})
            }

            // Ép render lại để cập nhật Auth State toàn hệ thống
            window.location.reload()

        } catch (err: unknown) {
            console.error("Login Error:", err)
            const serverError = (err as ApiErrorLike).response?.data?.message || (err as ApiErrorLike).response?.data?.error
            setError(serverError || "Tên đăng nhập hoặc mật khẩu không đúng")
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="flex min-h-screen items-center justify-center bg-brand-light px-4">
            <form
                onSubmit={handleSubmit}
                className="w-full max-w-md rounded-3xl bg-white p-8 shadow-lg animate-in fade-in duration-500"
            >
                <div className="text-center">
                    <h1 className="text-3xl font-bold text-brand-dark">Đăng nhập</h1>
                    <p className="mt-2 text-sm text-brand-gray">Chào mừng quay lại NovaGear</p>
                </div>

                <div className="mt-8 space-y-4">
                    <div className="space-y-1">
                        <label className="ml-1 text-xs font-bold uppercase text-brand-gray">Tên đăng nhập</label>
                        <input
                            type="text"
                            placeholder="Nhập username..."
                            className="w-full rounded-xl border border-gray-200 px-4 py-3 outline-none focus:border-brand-dark transition-all"
                            value={form.username}
                            onChange={(e) => setForm({...form, username: e.target.value})}
                            required
                        />
                    </div>

                    <div className="space-y-1">
                        <label className="ml-1 text-xs font-bold uppercase text-brand-gray">Mật khẩu</label>
                        <input
                            type="password"
                            placeholder="••••••••"
                            className="w-full rounded-xl border border-gray-200 px-4 py-3 outline-none focus:border-brand-dark transition-all"
                            value={form.password}
                            onChange={(e) => setForm({...form, password: e.target.value})}
                            required
                        />
                    </div>
                </div>

                {error && (
                    <div className="mt-4 rounded-xl border border-red-100 bg-red-50 p-3">
                        <p className="text-xs font-medium text-red-500">{error}</p>
                    </div>
                )}

                <button
                    type="submit"
                    disabled={loading}
                    className="mt-8 w-full rounded-xl bg-brand-dark py-3.5 font-bold text-white shadow-md transition-all hover:bg-black disabled:cursor-not-allowed disabled:bg-gray-400"
                >
                    {loading ? "Đang xử lý..." : "Đăng nhập ngay"}
                </button>

                <p className="mt-6 text-center text-sm text-brand-gray">
                    Chưa có tài khoản? <Link to="/register" className="font-bold text-blue-600 hover:underline">Đăng ký
                    ngay</Link>
                </p>
            </form>
        </div>
    )
}

import { useEffect, useState } from "react"
import { useNavigate, useParams, Link } from "react-router-dom"
import { getOrderDetail } from "../api/orderApi"
import type { Order } from "../types/order"
import { getToken } from "../utils/auth"

function getStatusText(status: Order["status"]) {
    switch (status) {
        case "PENDING":
            return "Chờ xác nhận"
        case "CONFIRMED":
            return "Đã xác nhận"
        case "PROCESSING":
            return "Đang xử lý"
        case "SHIPPING":
            return "Đang giao"
        case "DELIVERED":
            return "Đã giao"
        case "CANCELLED":
            return "Đã hủy"
        default:
            return status
    }
}

function formatCurrency(value: number) {
    return value.toLocaleString("vi-VN") + "đ"
}

export default function OrderDetailPage() {
    const { id = "" } = useParams()
    const navigate = useNavigate()
    const token = getToken()
    const [order, setOrder] = useState<Order | null>(null)
    const [loading, setLoading] = useState(Boolean(token && id))

    useEffect(() => {
        if (!token || !id) return

        let mounted = true

        getOrderDetail(id)
            .then((data) => {
                if (mounted) {
                    setOrder(data)
                }
            })
            .finally(() => {
                if (mounted) {
                    setLoading(false)
                }
            })

        return () => {
            mounted = false
        }
    }, [id, token])

    if (!token) {
        return (
            <div className="rounded-2xl bg-white p-8 shadow-sm">
                <h1 className="text-2xl font-bold">Chi tiết đơn hàng</h1>
                <p className="mt-3 text-brand-gray">
                    Bạn cần đăng nhập để xem chi tiết đơn.
                </p>
                <button
                    onClick={() => navigate("/login")}
                    className="mt-5 rounded-xl bg-brand-dark px-5 py-3 font-semibold text-white"
                >
                    Đi tới đăng nhập
                </button>
            </div>
        )
    }

    if (loading) return <div>Đang tải chi tiết đơn...</div>
    if (!order) return <div>Không tìm thấy đơn hàng</div>

    return (
        <div className="space-y-6">
            <div className="rounded-2xl bg-white p-6 shadow-sm">
                <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
                    <div>
                        <p className="text-sm text-brand-gray">Mã đơn</p>
                        <h1 className="text-2xl font-bold">
                            {order.orderCode || `#${order.id}`}
                        </h1>
                    </div>

                    <div className="text-right">
                        <p className="text-sm text-brand-gray">Trạng thái</p>
                        <p className="font-semibold text-brand-dark">
                            {getStatusText(order.status)}
                        </p>
                    </div>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-[1fr_320px]">
                <section className="space-y-4">
                    <div className="rounded-2xl bg-white p-5 shadow-sm">
                        <h2 className="text-xl font-bold">Sản phẩm</h2>

                        <div className="mt-4 space-y-4">
                            {order.items.map((item) => (
                                <div key={item.id} className="flex gap-4 border-b pb-4 last:border-b-0 last:pb-0">
                                    <img
                                        src={item.imageUrl || "https://via.placeholder.com/120"}
                                        alt={item.productName}
                                        className="h-20 w-20 rounded-xl object-cover"
                                    />

                                    <div className="flex-1">
                                        <h3 className="font-semibold">{item.productName}</h3>

                                        {item.variantLabel && (
                                            <p className="mt-1 text-sm text-brand-gray">
                                                Phiên bản: {item.variantLabel}
                                            </p>
                                        )}

                                        {item.variantSku && (
                                            <p className="mt-1 text-xs text-brand-gray">
                                                SKU: {item.variantSku}
                                            </p>
                                        )}

                                        <p className="mt-1 text-sm text-brand-gray">
                                            Số lượng: {item.quantity}
                                        </p>
                                        <p className="mt-1 font-bold text-brand-red">
                                            {formatCurrency(item.salePrice ?? item.price)}
                                        </p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="rounded-2xl bg-white p-5 shadow-sm">
                        <h2 className="text-xl font-bold">Thông tin nhận hàng</h2>
                        <div className="mt-4 space-y-2 text-sm text-brand-gray">
                            <p>Người nhận: {order.receiverName || "Đang cập nhật"}</p>
                            <p>Số điện thoại: {order.receiverPhone || "Đang cập nhật"}</p>
                            <p>Địa chỉ: {order.shippingAddress || "Đang cập nhật"}</p>
                            <p>Ghi chú: {order.note || "Không có"}</p>
                        </div>
                    </div>
                </section>

                <aside className="h-fit rounded-2xl bg-white p-5 shadow-sm">
                    <h2 className="text-xl font-bold">Thanh toán</h2>

                    <div className="mt-4 flex items-center justify-between">
                        <span className="text-sm text-brand-gray">Tổng cộng</span>
                        <span className="text-xl font-extrabold text-brand-red">
                            {formatCurrency(order.totalAmount)}
                        </span>
                    </div>

                    {order.status === "PENDING" && (
                        <div className="mt-6 flex flex-col gap-3">
                            <Link
                                to={`/payment/${order.id}`}
                                className="block w-full rounded-xl bg-brand-dark py-3 text-center font-semibold text-white transition-all hover:bg-opacity-90 active:scale-[0.98]"
                            >
                                Thanh toán ngay
                            </Link>

                            <div className="rounded-xl border border-amber-200 bg-amber-50 p-3 text-sm text-amber-700">
                                Backend hiện chưa thấy endpoint hủy đơn của user, nên FE tạm ẩn nút hủy.
                            </div>
                        </div>
                    )}
                </aside>
            </div>
        </div>
    )
}

import { useEffect, useState } from "react"
import { Link, useNavigate } from "react-router-dom"
import { getMyOrders } from "../api/orderApi"
import type { Order } from "../types/order"
import { getToken } from "../utils/auth"

function getStatusText(status: Order["status"]) {
    switch (status) {
        case "PENDING":
            return "Chờ xác nhận"
        case "CONFIRMED":
            return "Đã xác nhận"
        case "PROCESSING":
            return "Đang xử lý"
        case "SHIPPING":
            return "Đang giao"
        case "DELIVERED":
            return "Đã giao"
        case "CANCELLED":
            return "Đã hủy"
        default:
            return status
    }
}

function formatCurrency(value: number) {
    return value.toLocaleString("vi-VN") + "đ"
}

export default function OrdersPage() {
    const navigate = useNavigate()
    const token = getToken()
    const [items, setItems] = useState<Order[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        if (!token) {
            setLoading(false)
            return
        }

        getMyOrders()
            .then(setItems)
            .finally(() => setLoading(false))
    }, [token])

    if (!token) {
        return (
            <div className="rounded-2xl bg-white p-8 shadow-sm">
                <h1 className="text-2xl font-bold">Đơn hàng của tôi</h1>
                <p className="mt-3 text-brand-gray">
                    Bạn cần đăng nhập để xem đơn hàng.
                </p>
                <button
                    onClick={() => navigate("/login")}
                    className="mt-5 rounded-xl bg-brand-dark px-5 py-3 font-semibold text-white"
                >
                    Đi tới đăng nhập
                </button>
            </div>
        )
    }

    if (loading) return <div>Đang tải đơn hàng...</div>

    return (
        <div className="space-y-4">
            <div className="rounded-2xl bg-white p-5 shadow-sm">
                <h1 className="text-2xl font-bold">Đơn hàng của tôi</h1>
            </div>

            {items.length === 0 ? (
                <div className="rounded-2xl bg-white p-6 shadow-sm">
                    Bạn chưa có đơn hàng nào.
                </div>
            ) : (
                items.map((order) => (
                    <Link
                        key={order.id}
                        to={`/orders/${order.id}`}
                        className="block rounded-2xl bg-white p-5 shadow-sm transition hover:shadow-md"
                    >
                        <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
                            <div>
                                <p className="text-sm text-brand-gray">Mã đơn</p>
                                <h3 className="font-bold">
                                    {order.orderCode || `#${order.id}`}
                                </h3>
                                <p className="mt-1 text-xs text-brand-gray">
                                    {order.createdAt || "—"}
                                </p>
                            </div>

                            <div>
                                <p className="text-sm text-brand-gray">Trạng thái</p>
                                <p className="font-semibold text-brand-dark">
                                    {getStatusText(order.status)}
                                </p>
                            </div>

                            <div>
                                <p className="text-sm text-brand-gray">Tổng tiền</p>
                                <p className="font-bold text-brand-red">
                                    {formatCurrency(order.totalAmount)}
                                </p>
                            </div>
                        </div>

                        {order.items.length > 0 && (
                            <div className="mt-4 grid gap-3 md:grid-cols-2">
                                {order.items.slice(0, 2).map((item) => (
                                    <div
                                        key={item.id}
                                        className="rounded-xl border p-3"
                                    >
                                        <p className="font-medium">
                                            {item.productName || "Sản phẩm"}
                                        </p>

                                        {item.variantLabel && (
                                            <p className="mt-1 text-sm text-brand-gray">
                                                Phiên bản: {item.variantLabel}
                                            </p>
                                        )}

                                        {item.variantSku && (
                                            <p className="mt-1 text-xs text-brand-gray">
                                                SKU: {item.variantSku}
                                            </p>
                                        )}

                                        <p className="mt-2 text-sm text-brand-gray">
                                            SL: {item.quantity}
                                        </p>
                                    </div>
                                ))}
                            </div>
                        )}
                    </Link>
                ))
            )}
        </div>
    )
}

import { useEffect, useState } from "react"
import { Link, useNavigate } from "react-router-dom"
import { getMyOrders } from "../api/orderApi"
import type { Order } from "../types/order"
import { getToken } from "../utils/auth"

function getStatusText(status: Order["status"]) {
    switch (status) {
        case "PENDING":
            return "Chờ xác nhận"
        case "CONFIRMED":
            return "Đã xác nhận"
        case "PROCESSING":
            return "Đang xử lý"
        case "SHIPPING":
            return "Đang giao"
        case "DELIVERED":
            return "Đã giao"
        case "CANCELLED":
            return "Đã hủy"
        default:
            return status
    }
}

function formatCurrency(value: number) {
    return value.toLocaleString("vi-VN") + "đ"
}

export default function OrdersPage() {
    const navigate = useNavigate()
    const token = getToken()
    const [items, setItems] = useState<Order[]>([])
    const [loading, setLoading] = useState(Boolean(token))

    useEffect(() => {
        if (!token) return

        let mounted = true

        getMyOrders()
            .then((data) => {
                if (mounted) {
                    setItems(data)
                }
            })
            .finally(() => {
                if (mounted) {
                    setLoading(false)
                }
            })

        return () => {
            mounted = false
        }
    }, [token])

    if (!token) {
        return (
            <div className="rounded-2xl bg-white p-8 shadow-sm">
                <h1 className="text-2xl font-bold">Đơn hàng của tôi</h1>
                <p className="mt-3 text-brand-gray">
                    Bạn cần đăng nhập để xem đơn hàng.
                </p>
                <button
                    onClick={() => navigate("/login")}
                    className="mt-5 rounded-xl bg-brand-dark px-5 py-3 font-semibold text-white"
                >
                    Đi tới đăng nhập
                </button>
            </div>
        )
    }

    if (loading) return <div>Đang tải đơn hàng...</div>

    return (
        <div className="space-y-4">
            <div className="rounded-2xl bg-white p-5 shadow-sm">
                <h1 className="text-2xl font-bold">Đơn hàng của tôi</h1>
            </div>

            {items.length === 0 ? (
                <div className="rounded-2xl bg-white p-6 shadow-sm">
                    Bạn chưa có đơn hàng nào.
                </div>
            ) : (
                items.map((order) => (
                    <Link
                        key={order.id}
                        to={`/orders/${order.id}`}
                        className="block rounded-2xl bg-white p-5 shadow-sm transition hover:shadow-md"
                    >
                        <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
                            <div>
                                <p className="text-sm text-brand-gray">Mã đơn</p>
                                <h3 className="font-bold">
                                    {order.orderCode || `#${order.id}`}
                                </h3>
                                <p className="mt-1 text-xs text-brand-gray">
                                    {order.createdAt || "—"}
                                </p>
                            </div>

                            <div>
                                <p className="text-sm text-brand-gray">Trạng thái</p>
                                <p className="font-semibold text-brand-dark">
                                    {getStatusText(order.status)}
                                </p>
                            </div>

                            <div>
                                <p className="text-sm text-brand-gray">Tổng tiền</p>
                                <p className="font-bold text-brand-red">
                                    {formatCurrency(order.totalAmount)}
                                </p>
                            </div>
                        </div>

                        {order.items.length > 0 && (
                            <div className="mt-4 grid gap-3 md:grid-cols-2">
                                {order.items.slice(0, 2).map((item) => (
                                    <div
                                        key={item.id}
                                        className="rounded-xl border p-3"
                                    >
                                        <p className="font-medium">
                                            {item.productName || "Sản phẩm"}
                                        </p>

                                        {item.variantLabel && (
                                            <p className="mt-1 text-sm text-brand-gray">
                                                Phiên bản: {item.variantLabel}
                                            </p>
                                        )}

                                        {item.variantSku && (
                                            <p className="mt-1 text-xs text-brand-gray">
                                                SKU: {item.variantSku}
                                            </p>
                                        )}

                                        <p className="mt-2 text-sm text-brand-gray">
                                            SL: {item.quantity}
                                        </p>
                                    </div>
                                ))}
                            </div>
                        )}
                    </Link>
                ))
            )}
        </div>
    )
}

import { useEffect, useState } from "react"
import { useNavigate, useParams } from "react-router-dom"
import {
    createPayment,
    getPaymentByOrderId,
    mockPaymentFail,
    mockPaymentSuccess,
} from "../api/paymentApi"
import { getOrderDetail } from "../api/orderApi"
import type { Order } from "../types/order"
import type { Payment } from "../types/payment"
import { getToken } from "../utils/auth"

export default function PaymentPage() {
    const { orderId = "" } = useParams()
    const navigate = useNavigate()
    const token = getToken()

    const [order, setOrder] = useState<Order | null>(null)
    const [payment, setPayment] = useState<Payment | null>(null)
    const [method, setMethod] = useState("COD")
    const [loading, setLoading] = useState(true)
    const [creating, setCreating] = useState(false)
    const [mocking, setMocking] = useState(false)

    const loadData = async () => {
        if (!orderId) return

        try {
            const [orderData, paymentData] = await Promise.all([
                getOrderDetail(orderId),
                getPaymentByOrderId(orderId).catch(() => null),
            ])
            setOrder(orderData)
            setPayment(paymentData)
        } finally {
            setLoading(false)
        }
    }

    useEffect(() => {
        if (!token || !orderId) {
            setLoading(false)
            return
        }

        loadData().catch(console.error)
    }, [orderId, token])

    const handleCreatePayment = async () => {
        if (!order) return

        try {
            setCreating(true)
            const data = await createPayment(order.id, method)
            setPayment(data)

            if (data.paymentUrl) {
                window.location.href = data.paymentUrl
                return
            }

            navigate(`/payment/result?orderId=${order.id}&status=pending`)
        } catch (err) {
            console.error(err)
            alert("Tạo thanh toán thất bại")
        } finally {
            setCreating(false)
        }
    }

    const handleMock = async (type: "success" | "failed") => {
        if (!order) return

        try {
            setMocking(true)

            if (type === "success") {
                await mockPaymentSuccess(order.id)
                navigate(`/payment/result?orderId=${order.id}&status=success`)
            } else {
                await mockPaymentFail(order.id)
                navigate(`/payment/result?orderId=${order.id}&status=failed`)
            }
        } catch (err) {
            console.error(err)
            alert("Mock callback thất bại")
        } finally {
            setMocking(false)
        }
    }

    if (!token) {
        return (
            <div className="rounded-2xl bg-white p-8 shadow-sm">
                <h1 className="text-2xl font-bold">Thanh toán đơn hàng</h1>
                <p className="mt-3 text-brand-gray">Bạn cần đăng nhập để thanh toán.</p>
                <button
                    onClick={() => navigate("/login")}
                    className="mt-5 rounded-xl bg-brand-dark px-5 py-3 font-semibold text-white"
                >
                    Đi tới đăng nhập
                </button>
            </div>
        )
    }

    if (loading) return <div>Đang tải thông tin thanh toán...</div>
    if (!order) return <div>Không tìm thấy đơn hàng</div>

    return (
        <div className="grid gap-6 md:grid-cols-[1fr_360px]">
            <section className="rounded-2xl bg-white p-6 shadow-sm">
                <h1 className="text-2xl font-bold">Thanh toán đơn hàng</h1>
                <p className="mt-2 text-sm text-brand-gray">
                    Đơn {order.orderCode || `#${order.id}`}
                </p>

                <div className="mt-6 space-y-4">
                    <label className="flex cursor-pointer items-center gap-3 rounded-xl border p-4">
                        <input
                            type="radio"
                            name="paymentMethod"
                            value="COD"
                            checked={method === "COD"}
                            onChange={(e) => setMethod(e.target.value)}
                        />
                        <div>
                            <p className="font-semibold">Thanh toán khi nhận hàng</p>
                            <p className="text-sm text-brand-gray">Phù hợp khi bạn muốn xác nhận hàng trước.</p>
                        </div>
                    </label>

                    <label className="flex cursor-pointer items-center gap-3 rounded-xl border p-4">
                        <input
                            type="radio"
                            name="paymentMethod"
                            value="ONLINE"
                            checked={method === "ONLINE"}
                            onChange={(e) => setMethod(e.target.value)}
                        />
                        <div>
                            <p className="font-semibold">Thanh toán online</p>
                            <p className="text-sm text-brand-gray">Dùng khi backend hỗ trợ cổng thanh toán hoặc mock callback.</p>
                        </div>
                    </label>
                </div>

                <button
                    onClick={handleCreatePayment}
                    disabled={creating}
                    className="mt-6 rounded-xl bg-brand-dark px-6 py-3 font-semibold text-white disabled:opacity-60"
                >
                    {creating ? "Đang tạo thanh toán..." : "Xác nhận thanh toán"}
                </button>

                <div className="mt-6 rounded-2xl border bg-gray-50 p-4">
                    <h3 className="font-semibold">Test mock callback</h3>
                    <p className="mt-1 text-sm text-brand-gray">
                        Backend hiện có endpoint mock callback qua query params.
                    </p>

                    <div className="mt-4 flex gap-3">
                        <button
                            onClick={() => handleMock("success")}
                            disabled={mocking}
                            className="rounded-xl bg-green-600 px-4 py-2 font-semibold text-white disabled:opacity-60"
                        >
                            Mock success
                        </button>
                        <button
                            onClick={() => handleMock("failed")}
                            disabled={mocking}
                            className="rounded-xl border border-red-500 px-4 py-2 font-semibold text-red-500 disabled:opacity-60"
                        >
                            Mock failed
                        </button>
                    </div>
                </div>

                {payment && (
                    <div className="mt-6 rounded-2xl bg-gray-50 p-4 text-sm text-brand-gray">
                        <p>Mã thanh toán: {payment.id}</p>
                        <p>Trạng thái: {payment.status}</p>
                        <p>Phương thức: {payment.method}</p>
                    </div>
                )}
            </section>

            <aside className="h-fit rounded-2xl bg-white p-5 shadow-sm">
                <h2 className="text-xl font-bold">Tóm tắt đơn hàng</h2>

                <div className="mt-4 flex items-center justify-between text-sm">
                    <span>Mã đơn</span>
                    <span>{order.orderCode || `#${order.id}`}</span>
                </div>

                <div className="mt-2 flex items-center justify-between text-sm">
                    <span>Trạng thái</span>
                    <span>{order.status}</span>
                </div>

                <div className="mt-2 flex items-center justify-between text-sm">
                    <span>Người nhận</span>
                    <span>{order.receiverName || "—"}</span>
                </div>

                <div className="mt-4 border-t pt-4">
                    <div className="flex items-center justify-between">
                        <span className="font-semibold">Tổng cộng</span>
                        <span className="text-xl font-extrabold text-brand-red">
                            {order.totalAmount.toLocaleString("vi-VN")}đ
                        </span>
                    </div>
                </div>
            </aside>
        </div>
    )
}

