                            Kết quả tìm kiếm cho: <span className="font-semibold">{keyword}</span>
                        </p>
                    )}
                    <p className="mt-2 text-sm text-slate-500">Tim thay {filtered.length} san pham</p>
                </div>

                {loading ? (
                    <div className="rounded-xl bg-white px-4 py-8 text-center text-slate-500 shadow-sm">Dang tai...</div>
                ) : (
                    <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
                        {filtered.map((product) => (
                            <ProductCard key={product.id} product={product} />
                        ))}
                    </div>
                )}
            </section>
        </div>
    )
}

import {useEffect, useState} from "react"
import {useNavigate} from "react-router-dom"
import {getMyProfile} from "../api/userApi"
import {useAuth} from "../hooks/useAuth"

function isAdminRole(role?: string | null) {
    if (!role) return false
    return role === "ADMIN" || role === "ROLE_ADMIN" || role.includes("ADMIN")
}

export default function ProfilePage() {
    const navigate = useNavigate()
    const {user, loading, logout} = useAuth()
    const [profile, setProfile] = useState<any>(null)
    const [profileLoading, setProfileLoading] = useState(true)

    useEffect(() => {
        const loadProfile = async () => {
            try {
                setProfileLoading(true)
                const data = await getMyProfile()
                setProfile(data)
            } catch (err) {
                console.error(err)
                setProfile(null)
            } finally {
                setProfileLoading(false)
            }
        }

        loadProfile()
    }, [])

    const handleLogout = () => {
        logout()
        navigate("/")
        window.location.reload()
    }

    if (loading || profileLoading) {
        return <div>Đang tải thông tin tài khoản...</div>
    }

    return (
        <div className="mx-auto max-w-4xl space-y-6">
            <div className="rounded-3xl bg-white p-6 shadow-sm">
